```cpp
#include <vector>
#include <string>
#include <regex>
#include <algorithm>
#include <functional>

std::vector<std::string> solve(std::vector<std::string> code, std::vector<std::string> businessLine, std::vector<bool> isActive) {
    std::vector<std::pair<std::string, std::string>> valid;
    for (size_t i = 0; i < code.size(); ++i) {
        const std::string& c = code[i];
        const std::string& b = businessLine[i];
        const bool a = isActive[i];
        if (c.empty()) continue;
        std::regex pattern("^[a-zA-Z0-9_]+$");
        if (!std::regex_match(c, pattern)) continue;
        if (b != "electronics" && b != "grocery" && b != "pharmacy" && b != "restaurant") continue;
        if (!a) continue;
        valid.push_back({b, c});
    }

    std::vector<std::string> order = {"electronics", "grocery", "pharmacy", "restaurant"};
    std::sort(valid.begin(), valid.end(), [&](const std::pair<std::string, std::string>& a, const std::pair<std::string, std::string>& b) {
        size_t idxA = std::find(order.begin(), order.end(), a.first) - order.begin();
        size_t idxB = std::find(order.begin(), order.end(), b.first) - order.begin();
        if (idxA != idxB) return idxA < idxB;
        return a.second < b.second;
    });

    std::vector<std::string> result;
    for (const auto& p : valid) {
        result.push_back(p.second);
    }
    return result;
}
```

