#include <iterator>
#include <functional>

std::vector<std::string> solve(std::vector<std::string> code, std::vector<std::string> businessLine, std::vector<bool> isActive) {
    std::vector<std::string> allowedBusiness = {"electronics", "grocery", "pharmacy", "restaurant"};
    std::regex codeRegex("^[a-zA-Z0-9_]+$");
    std::vector<std::pair<std::string, std::string>> validCoupons;

    for (size_t i = 0; i < code.size(); ++i) {
        const std::string& c = code[i];
        const std::string& b = businessLine[i];
        const bool a = isActive[i];

        if (c.empty()) continue;

        if (!std::regex_match(c, codeRegex)) continue;

        if (std::find(allowedBusiness.begin(), allowedBusiness.end(), b) == allowedBusiness.end()) continue;

        if (!a) continue;

        validCoupons.push_back({b, c});
    }

    std::sort(validCoupons.begin(), validCoupons.end(), [&](const auto& a, const auto& b) {
        size_t idxA = std::distance(allowedBusiness.begin(), std::find(allowedBusiness.begin(), allowedBusiness.end(), a.first));
        size_t idxB = std::distance(allowedBusiness.begin(), std::find(allowedBusiness.begin(), allowedBusiness.end(), b.first));
        if (idxA != idxB) return idxA < idxB;
        return a.second < b.second;
    });

    std::vector<std::string> result;
    for (const auto& pair : validCoupons) {
        result.push_back(pair.second);
    }

    return result;
}
