#include <vector>
#include <string>
#include <regex>
#include <algorithm>
#include <map>
#include <set>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<pair<string, string>> validCoupons;
    set<string> allowedBusiness = {"electronics", "grocery", "pharmacy", "restaurant"};
    vector<string> order = {"electronics", "grocery", "pharmacy", "restaurant"};
    map<string, int> businessOrder;
    for (int i = 0; i < order.size(); ++i) {
        businessOrder[order[i]] = i;
    }
    for (int i = 0; i < code.size(); ++i) {
        string c = code[i];
        string b = businessLine[i];
        bool a = isActive[i];
        if (c.empty()) continue;
        if (!regex_match(c, regex("^[a-zA-Z0-9_]+$"))) continue;
        if (allowedBusiness.find(b) == allowedBusiness.end()) continue;
        if (!a) continue;
        validCoupons.push_back({c, b});
    }

    sort(validCoupons.begin(), validCoupons.end(), [&](pair<string, string> a, pair<string, string> b) {
        int idxA = businessOrder[a.second];
        int idxB = businessOrder[b.second];
        if (idxA != idxB) return idxA < idxB;
        return a.first < b.first;
    });

    vector<string> result;
    for (auto& p : validCoupons) {
        result.push_back(p.first);
    }
    return result;
}
```

