```cpp
#include <vector>
#include <string>
#include <regex>
#include <algorithm>
#include <functional>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> order = {"electronics", "grocery", "pharmacy", "restaurant"};
    regex codeRegex("^[a-zA-Z0-9_]+$");
    vector<pair<string, string>> validCoupons;

    for (size_t i = 0; i < code.size(); ++i) {
        if (code[i].empty()) continue;
        if (!regex_match(code[i], codeRegex)) continue;
        string b = businessLine[i];
        if (b != "electronics" && b != "grocery" && b != "pharmacy" && b != "restaurant") continue;
        if (!isActive[i]) continue;
        validCoupons.push_back({b, code[i]});
    }

    sort(validCoupons.begin(), validCoupons.end(), [&](const pair<string, string>& a, const pair<string, string>& b) {
        int idxA = find(order.begin(), order.end(), a.first) - order.begin();
        int idxB = find(order.begin(), order.end(), b.first) - order.begin();
        if (idxA != idxB) return idxA < idxB;
        return a.second < b.second;
    });

    vector<string> result;
    for (const auto& p : validCoupons) {
        result.push_back(p.second);
    }
    return result;
}
